  { id: 'erding_germany', location: 'Erding', country: 'Germany', year: 1417, lat: 48.3060, lng: 11.9069, title: 'Eucharistic Miracle of Erding', description: 'In 1417, a peasant stole a Host. As he tried to escape, the Host slipped from his hand and hovered in the air, radiating light until recovered by the clergy.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=germania&wh=erding&ct=Erding%2C%201417' },
  { id: 'kranenburg_germany', location: 'Kranenburg', country: 'Germany', year: 1280, lat: 51.7892, lng: 6.0083, title: 'Eucharistic Miracle of Kranenburg', description: 'In 1280, a priest dropped a consecrated Host into a hollow in a tree. Years later, a wooden crucifix carved from the tree began to bleed, leading to a major pilgrimage.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=germania&wh=kranenburg_bei_kleve&ct=Kranenburg%2C%201280' },
  { id: 'regensburg_germany', location: 'Regensburg', country: 'Germany', year: 1255, lat: 49.0134, lng: 12.1016, title: 'Eucharistic Miracle of Regensburg', description: 'In 1255, a priest doubted the Real Presence. During Mass, the wooden crucifix on the altar came to life, and Jesus took the chalice from the priest\'s hand.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=germania&wh=regensburg&ct=Regensburg%2C%201255' },
  { id: 'wilsnack_germany', location: 'Wilsnack', country: 'Germany', year: 1383, lat: 52.9556, lng: 11.9444, title: 'Eucharistic Miracle of Wilsnack', description: 'In 1383, a church was destroyed by fire, but three consecrated Hosts survived completely intact on the altar, covered in drops of fresh blood.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=germania&wh=wilsnack&ct=Wilsnack%2C%201383' },
  { id: 'weingarten_germany', location: 'Weingarten', country: 'Germany', year: 1056, lat: 47.8083, lng: 9.6417, title: 'Eucharistic Miracle of Weingarten', description: 'The monastery of Weingarten preserves the relic of the Precious Blood of Jesus, which was verified by several miracles and has been venerated since the 11th century.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=germania&wh=weingarten&ct=Weingarten' },

  // Martinique & Reunion
  { id: 'morne_rouge_martinique', location: 'Morne-Rouge', country: 'Martinique', year: 1902, lat: 14.7725, lng: -61.1350, title: 'Eucharistic Miracle of Morne-Rouge', description: 'In 1902, during the volcanic eruption of Mount Pelée, the sacred Host inside the monstrance showed the face of Jesus crowned with thorns in front of the fleeing population.', approvalStatus: 'Traditionally Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=isole_della_martinica&wh=morne-rouge&ct=Morne-Rouge%2C%201902' },
  { id: 'saint_andre_reunion', location: 'Saint-André', country: 'Reunion Islands', year: 1902, lat: -20.9606, lng: 55.6508, title: 'Eucharistic Miracle of Saint-André', description: 'In 1902, during adoration of the Blessed Sacrament, the face of Jesus and a crown of thorns appeared inside the Host, witnessed by the parish priest and the congregation.', approvalStatus: 'Bishop Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=isole_della_reunion&wh=saint-andre_de_la_reunion&ct=Saint-Andr%C3%A9%20de%20la%20R%C3%A9union%2C%201902' },

  // Italy
  { id: 'alatri_italy', location: 'Alatri', country: 'Italy', year: 1228, lat: 41.7264, lng: 13.3425, title: 'Eucharistic Miracle of Alatri', description: 'In 1228, a young woman took the Host home in a cloth. Three days later, she found that the Host had transformed into bleeding flesh, which is preserved in Alatri Cathedral.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=alatri&ct=Alatri%2C%201228' },
  { id: 'assisi_clara_italy', location: 'Assisi', country: 'Italy', year: 1240, lat: 43.0707, lng: 12.6178, title: 'Eucharistic Miracle of Assisi', description: 'In 1240, St. Clare of Assisi turned back invading Saracen soldiers by holding up the monstrance containing the Blessed Sacrament at the gates of the convent.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=santachiaradassisi&ct=Saint%20Clare%20of%20Assisi%2C%201240' },
  { id: 'asti_italy_1535', location: 'Asti', country: 'Italy', year: 1535, lat: 44.9000, lng: 8.2069, title: 'Eucharistic Miracle of Asti', description: 'In 1535, a priest celebrating Mass broke the Host, and blood began to flow from the break, filling the chalice and staining the corporal and altar.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=italia&wh=asti&ct=Asti%2C%201535' },
  { id: 'bagno_di_romagna_italy', location: 'Bagno di Romagna', country: 'Italy', year: 1412, lat: 43.8333, lng: 11.9667, title: 'Eucharistic Miracle of Bagno di Romagna', description: 'In 1412, a priest doubting the Real Presence saw the consecrated wine boil and overflow the chalice as blood, staining the corporal, which remains preserved.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=bagnodiromagna&ct=Bagno%20di%20Romagna%2C%201412' },
  { id: 'canosio_italy', location: 'Canosio', country: 'Italy', year: 1630, lat: 44.4500, lng: 7.3000, title: 'Eucharistic Miracle of Canosio', description: 'In 1630, a priest stopped a devastating flood of the Maira torrent by blessing the rising waters with the Blessed Sacrament, which instantly receded.', approvalStatus: 'Traditionally Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=canosio&ct=Canosio%2C%201630' },
  { id: 'cava_dei_tirreni_italy', location: 'Cava de\' Tirreni', country: 'Italy', year: 1656, lat: 40.7011, lng: 14.7083, title: 'Eucharistic Miracle of Cava de\' Tirreni', description: 'In 1656, a devastating plague was halted when the abbot carried the Blessed Sacrament in procession, blessing the town from the hill of Castle Saint Adiutore.', approvalStatus: 'Traditionally Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=cavadeitirreni&ct=Cava%20dei%20Tirreni,%201656' },
  { id: 'dronero_italy', location: 'Dronero', country: 'Italy', year: 1631, lat: 44.4667, lng: 7.3667, title: 'Eucharistic Miracle of Dronero', description: 'In 1631, a massive fire threatened to consume the town of Dronero. A priest held up the Blessed Sacrament, and the flames immediately died out, saving the town.', approvalStatus: 'Traditionally Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=dronero&ct=Dronero%2C%201631' },
  { id: 'san_mauro_la_bruca_italy', location: 'San Mauro La Bruca', country: 'Italy', year: 1969, lat: 40.1167, lng: 15.2833, title: 'Eucharistic Miracle of San Mauro La Bruca', description: 'In 1969, thieves stole a ciborium but threw away 63 consecrated Hosts. The Hosts were recovered in perfect condition and have remained incorrupt ever since.', approvalStatus: 'Bishop Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=dronero&ct=San%20Mauro%20La%20Bruca%2C%201969' },
  { id: 'ferrara_italy', location: 'Ferrara', country: 'Italy', year: 1171, lat: 44.8381, lng: 11.6198, title: 'Eucharistic Miracle of Ferrara', description: 'In 1171, a priest celebrating Mass saw the Host turn into blood, spraying the vault above the altar with red drops, which are still visible today.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=ferrara&ct=Ferrara%2C%201171' },
  { id: 'florence_italy_1230', location: 'Florence', country: 'Italy', year: 1230, lat: 43.7696, lng: 11.2558, title: 'Eucharistic Miracle of Florence', description: 'In 1230, a priest left a few drops of consecrated wine in the chalice. The next day, the wine had turned into blood. The relic is preserved in the church of Sant\'Ambrogio.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=italia&wh=firenze&ct=Florence%2C%201230-1595' },
  { id: 'gruaro_italy', location: 'Gruaro', country: 'Italy', year: 1294, lat: 45.7500, lng: 12.8333, title: 'Eucharistic Miracle of Gruaro', description: 'In 1294, a woman washing the altar linen of the church of Gruaro found it stained with blood coming from a consecrated Host, which is preserved in Valvasone.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=gruaro&ct=Gruaro%20(Valvasone)%2C%201294' },
  { id: 'macerata_italy', location: 'Macerata', country: 'Italy', year: 1356, lat: 43.3003, lng: 13.4533, title: 'Eucharistic Miracle of Macerata', description: 'In 1356, a priest doubting the Real Presence saw blood gush from the Host when he broke it, staining the corporal, which is still venerated in Macerata.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=macerata&ct=Macerata%2C%201356' },
  { id: 'mogoro_italy', location: 'Mogoro', country: 'Italy', year: 1604, lat: 39.6833, lng: 8.7833, title: 'Eucharistic Miracle of Mogoro', description: 'In 1604, two sinners received communion but spat the Hosts onto the stone floor, where the Hosts left deep, bleeding imprints that can still be seen today.', approvalStatus: 'Bishop Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=mogoro&ct=Mogoro%2C%201604' },
  { id: 'morrovalle_italy', location: 'Morrovalle', country: 'Italy', year: 1560, lat: 43.3167, lng: 13.5833, title: 'Eucharistic Miracle of Morrovalle', description: 'In 1560, a fire completely destroyed the church, but the consecrated Host was found intact under the ashes ten days later, radiating a soft light.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=morrovalle&ct=Morrovalle%2C%201560' },
  { id: 'offida_italy', location: 'Offida', country: 'Italy', year: 1273, lat: 42.9333, lng: 13.7000, title: 'Eucharistic Miracle of Offida', description: 'In 1273, a woman threw a Host into a fire. The Host transformed into bleeding flesh and remained untouched by the flames. The relic is kept in the church of St. Augustine.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=offida&ct=Offida%2C%201273-1280' },
  { id: 'patierno_naples_italy', location: 'Patierno', country: 'Italy', year: 1772, lat: 40.8833, lng: 14.3000, title: 'Eucharistic Miracle of Patierno', description: 'In 1772, stolen Hosts were hidden in a field. They were found emitting a bright light and were recovered in perfect condition, accompanied by multiple miracles.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=patierno&ct=Patierno%20(Naples)%2C%201772' },
  { id: 'rimini_italy', location: 'Rimini', country: 'Italy', year: 1227, lat: 44.0583, lng: 12.5667, title: 'Eucharistic Miracle of Rimini', description: 'In 1227, St. Anthony of Padua proved the Real Presence to an heretic when a hungry mule knelt down to adore the Blessed Sacrament instead of eating oats.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=rimini&ct=Rimini%2C%201227' },
  { id: 'rome_italy_600', location: 'Rome', country: 'Italy', year: 600, lat: 41.9028, lng: 12.4964, title: 'Eucharistic Miracle of Rome', description: 'In the 6th century, Pope Gregory the Great saw a consecrated Host turn into visible flesh to cure the doubt of a woman who had baked the bread.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=romab&ct=Rome%2C%201610' },
  { id: 'rosano_italy', location: 'Rosano', country: 'Italy', year: 1948, lat: 43.7667, lng: 11.4167, title: 'Eucharistic Miracle of Rosano', description: 'In 1948, the face of Jesus appeared inside the Host during adoration in the monastery of Rosano, witnessed by the nuns and parishioners.', approvalStatus: 'Bishop Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=rosano&ct=Rosano%2C%201948' },
  { id: 'peter_damian_italy', location: 'Faenza', country: 'Italy', year: 1050, lat: 44.2833, lng: 11.8833, title: 'Eucharistic Miracle of St. Peter Damian', description: 'In the 11th century, St. Peter Damian documented a miracle where a woman stole a Host. The Host bled onto the cloth, and when shown to him, he verified its authenticity.', approvalStatus: 'Traditionally Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=sanpierdamiani&ct=S.%20Peter%20Damian%2C%20XI%20cent.' },
  { id: 'salzano_italy', location: 'Salzano', country: 'Italy', year: 1517, lat: 45.5417, lng: 12.1167, title: 'Eucharistic Miracle of Salzano', description: 'In 1517, a priest celebrating Mass saw the Host bleed, staining the corporal and the altar, demonstrating the Real Presence to the entire congregation.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=salzano&ct=Salzano%2C%201517' },
  { id: 'scala_italy', location: 'Scala', country: 'Italy', year: 1732, lat: 40.6542, lng: 14.6067, title: 'Eucharistic Miracle of Scala', description: 'In 1732, during adoration of the Blessed Sacrament, the instruments of the Passion (cross, crown of thorns, nails) appeared inside the Host, witnessed by St. Alphonsus Liguori.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=sanpierdamiani&ct=Scala%2C%201732' },
  { id: 'trani_italy', location: 'Trani', country: 'Italy', year: 1000, lat: 41.2725, lng: 16.4178, title: 'Eucharistic Miracle of Trani', description: 'In the 11th century, an heretic woman fried a consecrated Host in oil. The Host began to bleed profusely, overflowing the pan and spilling onto the floor.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=trani&ct=Trani%2C%20XI%20sec.' },
  { id: 'turin_italy_1453', location: 'Turin', country: 'Italy', year: 1453, lat: 45.0703, lng: 7.6869, title: 'Eucharistic Miracle of Turin (1453)', description: 'In 1453, a stolen monstrance containing a Host fell from a donkey. The Host rose into the air, radiating light, and remained suspended until the bishop arrived.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=torinob&ct=Turin%2C%201640' },
  { id: 'veroli_italy', location: 'Veroli', country: 'Italy', year: 1570, lat: 41.6903, lng: 13.4194, title: 'Eucharistic Miracle of Veroli', description: 'In 1570, during adoration, the face of Jesus and a cross appeared inside the Host, witnessed by many townspeople and verified by ecclesiastical authorities.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=veroli&ct=Veroli%2C%201570' },
  { id: 'volterra_italy', location: 'Volterra', country: 'Italy', year: 1472, lat: 43.4000, lng: 10.8667, title: 'Eucharistic Miracle of Volterra', description: 'In 1472, a soldier stole a pyx containing a Host. As he tried to throw it away, the Host hovered in the air and bled, leading to the conversion of the soldier.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=italia&wh=volterra&ct=Volterra%2C%201472' },

  // Netherlands
  { id: 'alkmaar_netherlands', location: 'Alkmaar', country: 'Netherlands', year: 1429, lat: 52.6325, lng: 4.7536, title: 'Eucharistic Miracle of Alkmaar', description: 'In 1429, a priest spilled consecrated wine onto his vestments. The wine turned to blood and could not be washed out. The blood-stained vestments are preserved.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=alkmaar&ct=Alkmaar%2C%201429' },
  { id: 'bergen_netherlands', location: 'Bergen', country: 'Netherlands', year: 1421, lat: 52.6708, lng: 4.7042, title: 'Eucharistic Miracle of Bergen', description: 'In 1421, a flood destroyed the church, and the consecrated Hosts were swept away. They were later found intact, with the water around them keeping them dry.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=bergen&ct=Bergen%2C%201421' },
  { id: 'boxmeer_netherlands', location: 'Boxmeer', country: 'Netherlands', year: 1400, lat: 51.6444, lng: 5.9528, title: 'Eucharistic Miracle of Boxmeer', description: 'In 1400, a priest doubted the Real Presence. During Mass, a drop of blood fell from the Host into the chalice, and the wine turned to blood and overflowed.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=boxmeer&ct=Boxmeer%2C%201400' },
  { id: 'boxtel_netherlands', location: 'Boxtel', country: 'Netherlands', year: 1380, lat: 51.5897, lng: 5.3283, title: 'Eucharistic Miracle of Boxtel', description: 'In 1380, a priest knocked over the chalice, spilling consecrated wine onto the altar cloth. The wine turned into blood and formed the image of Christ.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=boxtel-hoogstraten&ct=Boxtel-Hoogstraten%2C%201380' },
  { id: 'breda_netherlands', location: 'Breda', country: 'Netherlands', year: 1300, lat: 51.5719, lng: 4.7683, title: 'Eucharistic Miracle of Breda', description: 'In 1300, a consecrated Host was hidden in a field to prevent profanation. It was found years later completely intact and radiating a soft light.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=breda-niervaart&ct=Breda-Niervaart%2C%201300' },
  { id: 'meerssen_netherlands', location: 'Meerssen', country: 'Netherlands', year: 1222, lat: 50.8833, lng: 5.7500, title: 'Eucharistic Miracle of Meerssen', description: 'In 1222, a priest celebrant saw the Host bleed during Mass. In 1465, a fire destroyed the church, but the Host was found intact on the altar, untouched.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=meerssen&ct=Meerssen%2C%201222-1465' },
  { id: 'stiphout_netherlands', location: 'Stiphout', country: 'Netherlands', year: 1342, lat: 51.4917, lng: 5.6167, title: 'Eucharistic Miracle of Stiphout', description: 'In 1342, a fire destroyed the church, but a local peasant rushed inside and retrieved the Blessed Sacrament, which was untouched by the flames.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=olanda&wh=stiphout&ct=Stiphout%2C%201342' },

  // Peru
  { id: 'eten_peru', location: 'Eten', country: 'Peru', year: 1649, lat: -6.9039, lng: -79.8631, title: 'Eucharistic Miracle of Eten', description: 'In 1649, the face of the Child Jesus and three white hearts appeared inside the Host during adoration, witnessed by the priest and the congregation.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=peru&wh=eten&ct=Eten%2C%201649' },

  // Poland
  { id: 'glotowo_poland', location: 'Glotowo', country: 'Poland', year: 1290, lat: 53.9531, lng: 20.4072, title: 'Eucharistic Miracle of Glotowo', description: 'In 1290, a stolen Host was buried in a field. It was found years later when oxen knelt down in front of it, and the Host was found emitting a bright light.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=polonia&wh=glotowo&ct=Glotowo%2C%201290' },

  // Spain
  { id: 'alboraya_spain', location: 'Alboraya', country: 'Spain', year: 1348, lat: 39.5000, lng: -0.3500, title: 'Eucharistic Miracle of Alboraya-Almácera', description: 'In 1348, a priest carrying communion to the sick fell into a river, losing the Hosts. The Hosts were found in the mouths of fish who held them up, waiting to return them.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=spagna&wh=alboraya-almacera&ct=Alboraya-Almac%C3%A9ra%2C%201348' },
  { id: 'alcala_spain', location: 'Alcalá de Henares', country: 'Spain', year: 1597, lat: 40.4819, lng: -3.3636, title: 'Eucharistic Miracle of Alcalá', description: 'In 1597, a penitent returned stolen Hosts. The Hosts were kept in a drawer for years and remained completely fresh and incorrupt, verified by theologians.', approvalStatus: 'Vatican Approved' , sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=alcala&ct=Alcal%C3%A0%2C%201597' },
  { id: 'alcoy_spain', location: 'Alcoy', country: 'Spain', year: 1568, lat: 38.7056, lng: -0.4744, title: 'Eucharistic Miracle of Alcoy', description: 'In 1568, a thief stole a ciborium. The Hosts were recovered after a local resident had a vision of where they were hidden, and they were found intact.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=alcoy&ct=Alcoy%2C%201568' },
  { id: 'caravaca_spain', location: 'Caravaca de la Cruz', country: 'Spain', year: 1231, lat: 38.1064, lng: -1.8594, title: 'Eucharistic Miracle of Caravaca de la Cruz', description: 'In 1231, two angels appeared carrying a double-armed cross (the Cross of Caravaca) during Mass celebrated by a priest in front of Moorish captors.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=caravaca_de_la_cruz&ct=Caravaca%20de%20la%20Cruz%2C%201231' },
  { id: 'cimballa_spain', location: 'Cimballa', country: 'Spain', year: 1370, lat: 41.2167, lng: -1.7833, title: 'Eucharistic Miracle of Cimballa', description: 'In 1370, a priest doubted the Real Presence. During Mass, the Host began to bleed onto the corporal, leaving a permanent stain of blood that is still venerated.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=cimballa&ct=Cimballa%2C%201370' },
  { id: 'gerona_spain', location: 'Gerona', country: 'Spain', year: 1297, lat: 41.9794, lng: 2.8214, title: 'Eucharistic Miracle of Gerona', description: 'In 1297, a priest celebrating Mass saw the Host bleed. The blood stained the corporal, and the relic was preserved and venerated in the Cathedral of Girona.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=gerona&ct=Gerona%2C%201297' },
  { id: 'escorial_spain', location: 'El Escorial', country: 'Spain', year: 1572, lat: 40.5919, lng: -4.1308, title: 'Eucharistic Miracle of Gorkum-El Escorial', description: 'In 1572, Protestant soldiers profaned a consecrated Host by stepping on it. The Host bled, and the relic was later given to King Philip II and kept in El Escorial.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=gorkum-el_escorial&ct=Gorkum-El%20Escorial%2C%201572' },
  { id: 'guadalupe_spain_1420', location: 'Guadalupe', country: 'Spain', year: 1420, lat: 39.4500, lng: -5.3333, title: 'Eucharistic Miracle of Guadalupe', description: 'In 1420, during Mass, the Host was seen to turn into bleeding flesh, and the wine turned to blood, filling the chalice, witnessed by King John II of Castile.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=miracoli&wh=guadalupe-messico&ct=Guadalupe%2C%20Mexico%2C%20Juan%20Diego%2C%201531' },
  { id: 'ivorra_spain', location: 'Ivorra', country: 'Spain', year: 1010, lat: 41.7725, lng: 1.3856, title: 'Eucharistic Miracle of Ivorra', description: 'In 1010, a priest celebrating Mass doubted the Real Presence. The wine turned to blood, overflowing the chalice and staining the altar cloth, which is preserved.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_c.html?nat=spagna&wh=ivorra&ct=Ivorra%2C%201010' },
  { id: 'moncada_spain', location: 'Moncada', country: 'Spain', year: 1392, lat: 39.5444, lng: -0.3958, title: 'Eucharistic Miracle of Moncada', description: 'In 1392, a priest saw the Child Jesus appear in the Host during Mass, and the Host bled, confirming the Real Presence to the congregation.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=moncada&ct=Moncada%2C%201392' },
  { id: 'montserrat_spain_1657', location: 'Montserrat', country: 'Spain', year: 1657, lat: 41.5933, lng: 1.8375, title: 'Eucharistic Miracle of Montserrat', description: 'In 1657, during Mass, the face of Jesus appeared inside the Host, and a series of miracles occurred in the monastery, leading to increased devotion.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=montserrat&ct=Montserrat%2C%201657' },
  { id: 'cebreiro_spain', location: 'O\'Cebreiro', country: 'Spain', year: 1300, lat: 42.7000, lng: -7.0333, title: 'Eucharistic Miracle of O\'Cebreiro', description: 'In 1300, a peasant climbed the mountain in a snowstorm to attend Mass. The doubting priest saw the Host turn to flesh and the wine to blood, staining the corporal.', approvalStatus: 'Vatican Approved', sourceUrl: "https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=ocebreiro&ct=O'Cebreiro%2C%201300" },
  { id: 'onil_spain', location: 'Onil', country: 'Spain', year: 1824, lat: 38.6272, lng: -0.6728, title: 'Eucharistic Miracle of Onil', description: 'In 1824, a stolen Host was recovered after a woman saw a mysterious light in a field. The Host was found intact and has remained incorrupt ever since.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=spagna&wh=onil&ct=Onil%2C%201824' },
  { id: 'ponferrada_spain', location: 'Ponferrada', country: 'Spain', year: 1533, lat: 42.5467, lng: -6.5961, title: 'Eucharistic Miracle of Ponferrada', description: 'In 1533, a thief stole a tabernacle with Hosts. The tabernacle was found hidden in a field, and the Hosts were found intact and emitting a soft light.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=ponferrada&ct=Ponferrada%2C%201533' },
  { id: 'sant_joan_de_les_abadesses_spain', location: 'Sant Joan de les Abadesses', country: 'Spain', year: 1251, lat: 42.2333, lng: 2.2833, title: 'Eucharistic Miracle of Sant Joan de les Abadesses', description: 'In 1251, during a liturgical ceremony, the Host inside the monstrance was seen to bleed, staining the monstrance, which was preserved.', approvalStatus: 'Vatican Approved' , sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=s_j_de_las_abadeses&ct=S.%20John%20of%20the%20Abbesses%2C%201251' },
  { id: 'silla_spain', location: 'Silla', country: 'Spain', year: 1907, lat: 39.3667, lng: -0.4167, title: 'Eucharistic Miracle of Silla', description: 'In 1907, a priest dropped a consecrated Host. The Host was recovered and placed in a drawer. Years later, it was found completely intact and incorrupt.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=silla&ct=Silla%2C%201907' },
  { id: 'valencia_spain', location: 'Valencia', country: 'Spain', year: 1400, lat: 39.4699, lng: -0.3774, title: 'Eucharistic Miracle of Valencia', description: 'The Cathedral of Valencia preserves the Holy Chalice of the Last Supper, which has been verified by numerous historic records and papal visits.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=spagna&wh=valencia&ct=Valencia' },
  { id: 'zaragoza_spain_1427', location: 'Zaragoza', country: 'Spain', year: 1427, lat: 41.6488, lng: -0.8891, title: 'Eucharistic Miracle of Zaragoza', description: 'In 1427, a consecrated Host was stolen and hidden in a house. The Host was found emitting a bright light and was recovered in perfect condition.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda.html?nat=spagna&wh=zaragoza&ct=Zaragoza%2C%201427' },

  // Switzerland
  { id: 'ettiswil_switzerland', location: 'Ettiswil', country: 'Switzerland', year: 1447, lat: 47.1444, lng: 8.0194, title: 'Eucharistic Miracle of Ettiswil', description: 'In 1447, a stolen Host was buried in a field. It was found when oxen refused to step on the spot, and the Host was found hovering above the ground.', approvalStatus: 'Vatican Approved', sourceUrl: 'https://www.miracolieucaristici.org/en/Liste/scheda_b.html?nat=svizzera&wh=ettiswil&ct=Ettiswil%2C%201447' }
